mapper.select:
SELECT r.reserveId, r.roomId, m.roomName, TO_CHAR(r.reserveDate, 'YYYY-MM-DD') AS reserveDate, r.startTime, r.endTime, r.title, r.memo, r.attendees, r.reserveEmpId, r.reserveEmpName, r.reserveDeptName, r.status, TO_CHAR(r.regDate, 'YYYY-MM-DD HH24:MI') AS regDate FROM meetingReserve r JOIN meetingRoom m ON r.roomId = m.roomId WHERE r.reserveDate = TO_DATE(#{reserveDate}, 'YYYY-MM-DD') AND r.status = 'ACTIVE'
AND r.roomId = #{roomId}
ORDER BY r.startTime, m.roomName

mapper.update:
UPDATE meetingReserve
SET status = 'CANCEL'
WHERE reserveId = #{reserveId}

mapper.select:
SELECT COUNT(*) FROM meetingReserve
WHERE roomId = #{roomId}
  AND reserveDate = TO_DATE(#{reserveDate}, 'YYYY-MM-DD')
  AND status = 'ACTIVE'
  AND startTime < #{endTime}
  AND endTime > #{startTime}
